// colorize: compose terminal-styled strings. Depends on ansi-styles.
// Vendored equivalent, MIT. The bare-specifier import below walks up
// from this file's directory and finds ansi-styles in the consuming
// project's flat node_modules (npm-flat-layout convention).

import styles from "ansi-styles";

export function wrap(text, color) {
    const c = styles.fg[color];
    if (!c) return text;
    return c.open + text + c.close;
}

export function bold(text) {
    return styles.bold.open + text + styles.bold.close;
}

export function compose(text, ...styleNames) {
    let out = text;
    for (const name of styleNames) {
        if (name === "bold") out = styles.bold.open + out + styles.bold.close;
        else if (name === "italic") out = styles.italic.open + out + styles.italic.close;
        else if (name === "underline") out = styles.underline.open + out + styles.underline.close;
        else if (styles.fg[name]) out = styles.fg[name].open + out + styles.fg[name].close;
        else if (styles.bg[name.startsWith("bg-") ? name.slice(3) : ""]) {
            const c = styles.bg[name.slice(3)];
            out = c.open + out + c.close;
        }
    }
    return out;
}

export { styles };
export default { wrap, bold, compose, styles };
